import { useState, useEffect, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export const useSecureStorage = (key, initialValue = null) => {
  const [value, setValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadValue();
  }, [key]);

  const loadValue = async () => {
    try {
      setLoading(true);
      const storedValue = await secureStorage.getItem(key);
      setValue(storedValue || initialValue);
      setError(null);
    } catch (err) {
      setError(err);
      console.error('Error loading secure value:', err);
    } finally {
      setLoading(false);
    }
  };

  const updateValue = useCallback(async (newValue) => {
    try {
      setLoading(true);
      await secureStorage.setItem(key, newValue);
      setValue(newValue);
      setError(null);
      return true;
    } catch (err) {
      setError(err);
      console.error('Error updating secure value:', err);
      return false;
    } finally {
      setLoading(false);
    }
  }, [key]);

  const removeValue = useCallback(async () => {
    try {
      setLoading(true);
      await secureStorage.removeItem(key);
      setValue(initialValue);
      setError(null);
      return true;
    } catch (err) {
      setError(err);
      console.error('Error removing secure value:', err);
      return false;
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  return { value, loading, error, updateValue, removeValue, reload: loadValue };
};

