// App.js
import React, { useEffect, useState } from 'react';
import { View, Text, Button, StyleSheet, ScrollView, ActivityIndicator } from 'react-native';
import secureStorage from './utils/secureStorage';
import { useUserProfile, usePaymentInfo, useAuthTokens } from './hooks/useSecureStorage';

const App = () => {
  const { profile, loading: profileLoading, saveProfile, clearProfile } = useUserProfile();
  const { paymentInfo, loading: paymentLoading, savePaymentInfo, clearPaymentInfo } = usePaymentInfo();
  const { authToken, refreshToken, loading: tokenLoading, saveTokens, clearTokens } = useAuthTokens();

  const handleSaveProfile = async () => {
    const userData = {
      id: '12345',
      name: 'John Doe',
      email: 'john.doe@example.com',
      phone: '+1234567890',
      address: {
        street: '123 Main St',
        city: 'New York',
        state: 'NY',
        zip: '10001'
      }
    };
    await saveProfile(userData);
  };

  const handleSavePayment = async () => {
    const payment = {
      cardNumber: '4111111111111111',
      cardHolder: 'John Doe',
      expiryDate: '12/25',
      cvv: '123',
      billingAddress: {
        street: '123 Main St',
        city: 'New York',
        state: 'NY',
        zip: '10001'
      }
    };
    await savePaymentInfo(payment);
  };

  const handleSaveTokens = async () => {
    await saveTokens(
      'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4gRG9lIiwiaWF0IjoxNTE2MjM5MDIyfQ',
      'refresh_token_xyz123abc456def789'
    );
  };

  const handleClearAll = async () => {
    await clearProfile();
    await clearPaymentInfo();
    await clearTokens();
  };

  if (profileLoading || paymentLoading || tokenLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
      </View>
    );
  }

  return (
    <ScrollView style={styles.container}>
      <Text style={styles.title}>Secure Storage Demo</Text>
      
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>User Profile</Text>
        <Text style={styles.data}>{profile ? JSON.stringify(profile, null, 2) : 'No profile data'}</Text>
        <Button title="Save Profile" onPress={handleSaveProfile} />
        <Button title="Clear Profile" onPress={clearProfile} color="red" />
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Payment Info</Text>
        <Text style={styles.data}>{paymentInfo ? JSON.stringify(paymentInfo, null, 2) : 'No payment data'}</Text>
        <Button title="Save Payment" onPress={handleSavePayment} />
        <Button title="Clear Payment" onPress={clearPaymentInfo} color="red" />
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Auth Tokens</Text>
        <Text style={styles.data}>Auth: {authToken || 'No token'}</Text>
        <Text style={styles.data}>Refresh: {refreshToken || 'No token'}</Text>
        <Button title="Save Tokens" onPress={handleSaveTokens} />
        <Button title="Clear Tokens" onPress={clearTokens} color="red" />
      </View>

      <View style={styles.section}>
        <Button title="Clear All Data" onPress={handleClearAll} color="darkred" />
      </View>
    </ScrollView>
  );
};

